mapper.select:
declare @claimed table ( id bigint, patient_raw_data_id bigint, reqno varchar(64), data_date date, status varchar(32), attempt_count int, max_attempts int, raw_data_last_time datetime, source_batch_time datetime, available_at datetime, last_start_time datetime, last_finish_time datetime, last_error_message varchar(2000), create_time datetime, update_time datetime );
;with selected_reqnos as ( select top (#{patientLimit}) t.reqno from patient_raw_data_change_task t with (updlock, readpast, rowlock) where t.status in
#{status}
and t.available_at <= #{now} and t.attempt_count < t.max_attempts group by t.reqno order by min(t.available_at), min(t.create_time), min(t.id) ), claim_candidates as ( select t.id from patient_raw_data_change_task t with (updlock, readpast, rowlock) inner join selected_reqnos r on r.reqno = t.reqno where t.status in
#{status}
and t.available_at <= #{now} and t.attempt_count < t.max_attempts ) update t set t.status = #{runningStatus}, t.last_start_time = #{now}, t.update_time = #{now}, t.attempt_count = t.attempt_count + 1 output inserted.id, inserted.patient_raw_data_id, inserted.reqno, inserted.data_date, inserted.status, inserted.attempt_count, inserted.max_attempts, inserted.raw_data_last_time, inserted.source_batch_time, inserted.available_at, inserted.last_start_time, inserted.last_finish_time, inserted.last_error_message, inserted.create_time, inserted.update_time into @claimed from patient_raw_data_change_task t inner join claim_candidates c on c.id = t.id;
select id, patient_raw_data_id, reqno, data_date, status, attempt_count, max_attempts, raw_data_last_time, source_batch_time, available_at, last_start_time, last_finish_time, last_error_message, create_time, update_time from @claimed order by data_date asc, create_time asc, id asc
